        fprintf('  PASS: 32T still returns single config, RowNumber=%d\n', cfg32.RowNumber);
    else
        fprintf('  FAIL: 32T returned %d configs (expected 1)\n', numel(cfg32));
    end
catch e
    fprintf('  FAIL: %s\n', e.message);
end

fprintf('\n=== Done ===\n');
exit;
